package com.ruoyi.web.controller.mes; import com.ruoyi.common.core.controller.BaseController; import com.ruoyi.common.core.domain.AjaxResult; import com.ruoyi.common.core.page.TableDataInfo; import com.ruoyi.mes.purchase.domain.InventoryBalance; import com.ruoyi.mes.purchase.mapper.InventoryBalanceMapper; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/mes/purchase/inventory") public class InventoryBalanceController extends BaseController { private final InventoryBalanceMapper mapper; public InventoryBalanceController(InventoryBalanceMapper mapper){this.mapper=mapper;} @GetMapping("/list") public TableDataInfo list(InventoryBalance q){startPage();return getDataTable(mapper.selectList(q));} @GetMapping("/{id}") public AjaxResult get(@PathVariable Long id){return success(mapper.selectById(id));} @PostMapping public AjaxResult add(@RequestBody InventoryBalance o){o.setCreateBy(getUsername());return toAjax(mapper.insert(o));} @PutMapping public AjaxResult edit(@RequestBody InventoryBalance o){o.setUpdateBy(getUsername());return toAjax(mapper.update(o));} @DeleteMapping("/{ids}") public AjaxResult remove(@PathVariable Long[] ids){return toAjax(mapper.deleteByIds(ids));} }
